+        assert!(tree.is_valid(1));
+        assert_eq!(tree.depth(1).unwrap(), 1);
+        assert!(tree.get(0).unwrap().has_children());
+    }
+
+    #[test]
+    fn test_revoke_subtree() {
+        let mut tree = DerivationTree::<64>::new();
+        tree.add_root(0, 1).unwrap();
