+        assert_eq!(revoked, 4);
+        assert_eq!(tree.len(), 0);
+    }
+
+    #[test]
+    fn test_partial_revoke() {
+        let mut tree = DerivationTree::<64>::new();
+        tree.add_root(0, 1).unwrap();
+        tree.add_child(0, 1, 1, 1).unwrap();
