+        fn adapter_different_keys_different_sigs() {
+            let a1 = CryptoSignerAdapter::new(HmacSha256WitnessSigner::new([0x11u8; 32]));
+            let a2 = CryptoSignerAdapter::new(HmacSha256WitnessSigner::new([0x22u8; 32]));
