+        #[test]
+        fn adapter_with_witness_log_signed_append() {
+            let inner = HmacSha256WitnessSigner::new(test_key());
+            let adapter = CryptoSignerAdapter::new(inner);
+            let log = rvm_witness::WitnessLog::<16>::new();
+
