+
+    #[test]
+    fn alloc_all_pages_individually() {
+        let mut alloc = SmallAllocator::new(base()).unwrap();
+        let mut addrs = [PhysAddr::new(0); 16];
+        for (i, addr) in addrs.iter_mut().enumerate() {
+            *addr = alloc.alloc_pages(0).unwrap();
