+        // Now should be out of memory.
+        assert_eq!(alloc.alloc_pages(0), Err(RvmError::OutOfMemory));
+    }
+
+    /// A larger allocator for stress testing: 256 pages.
+    type MediumAllocator = BuddyAllocator<256, 16>;
+
