+        // Running -> Hibernated
+        assert!(valid_transition(PartitionState::Running, PartitionState::Hibernated));
+        // Hibernated -> Created
+        assert!(valid_transition(PartitionState::Hibernated, PartitionState::Created));
+        // Created -> Running (again)
